#!/usr/bin/env node
// Sync the hosted tool argument validator from @sogni/creative-agent into the
// public SDK. Keeps `src/Chat/hostedToolValidation.generated.ts` as a verbatim
// copy of `../sogni-creative-agent/src/backbone/reference/toolValidation.ts`
// with a "do not edit" banner so SDK consumers do not need to depend on the
// private creative-agent package while still inheriting the full validator
// (pattern auto-anchoring, bounds, oneOf/anyOf, nested recursion, etc.).
//
// Usage:
//   node scripts/sync-hosted-tool-validation.mjs          # write
//   node scripts/sync-hosted-tool-validation.mjs --check  # verify committed copy matches upstream

import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = dirname(dirname(fileURLToPath(import.meta.url)));
const creativeAgentRoot = process.env.SOGNI_CREATIVE_AGENT_DIR
  ? process.env.SOGNI_CREATIVE_AGENT_DIR
  : join(root, '..', 'sogni-creative-agent');

const upstreamRelative = 'src/backbone/reference/toolValidation.ts';
const upstreamPath = join(creativeAgentRoot, upstreamRelative);
const outputRelative = 'src/Chat/hostedToolValidation.generated.ts';
const outputPath = join(root, outputRelative);

if (!existsSync(upstreamPath)) {
  console.error(`Upstream validator not found at ${upstreamPath}.`);
  console.error('Set SOGNI_CREATIVE_AGENT_DIR or check out @sogni/creative-agent as a sibling repo.');
  process.exit(1);
}

const upstreamSource = readFileSync(upstreamPath, 'utf8');
const banner = [
  '/* eslint-disable */',
  '// Generated by scripts/sync-hosted-tool-validation.mjs.',
  `// Source: @sogni/creative-agent/${upstreamRelative}`,
  '// Do not edit by hand. Run `npm run sync:hosted-tool-validation` to refresh.',
  '',
].join('\n');

const expected = `${banner}${upstreamSource.endsWith('\n') ? upstreamSource : `${upstreamSource}\n`}`;

const checkMode = process.argv.includes('--check');

if (checkMode) {
  if (!existsSync(outputPath)) {
    console.error(`Missing generated file: ${outputRelative}`);
    console.error('Run `npm run sync:hosted-tool-validation` to create it.');
    process.exit(1);
  }
  const actual = readFileSync(outputPath, 'utf8');
  if (actual !== expected) {
    console.error(`Drift detected: ${outputRelative} does not match @sogni/creative-agent/${upstreamRelative}.`);
    console.error('Run `npm run sync:hosted-tool-validation` and commit the result.');
    process.exit(1);
  }
  console.log(`OK: ${outputRelative} matches upstream.`);
  process.exit(0);
}

writeFileSync(outputPath, expected);
console.log(`Synced ${outputRelative} from @sogni/creative-agent/${upstreamRelative}.`);
